animations.cssText:
@keyframes map-module__v1u8oa__pulse { 
  0% { opacity: 1; transform: scale(1); }
  50% { opacity: 0.8; transform: scale(1.5); }
  100% { opacity: 0; transform: scale(2); }
}

@keyframes booting-module__W1WDXW__turn-on { 
  0% { filter: brightness(30); opacity: 1; transform: scaleY(0.8) translate(0px, 0px); }
  3.5% { transform: scaleY(0.8) translateY(100%); }
  3.6% { opacity: 1; transform: scaleY(0.8) translateY(-100%); }
  9% { filter: brightness(30); opacity: 0; transform: scale(1.3, 0.6) translateY(100%); }
  11% { filter: contrast(0) brightness(0); opacity: 0; transform: scale(1) translate(0px, 0px); }
  100% { filter: contrast() brightness(1.2) saturate(1.3); opacity: 1; transform: scale(1) translate(0px, 0px); }
}

@keyframes booting-module__W1WDXW__jittery { 
  10% { transform: translate(-0.3px, -0.4px) scale(1); }
  20% { transform: translate(0.15px, 0.1px) scale(1); }
  30% { transform: translate(-0.2px, -0.25px) scale(1); }
  40% { transform: translate(0.05px, 0.1px) scale(1); }
  50% { transform: translate(-0.025px, -0.05px) scale(1); }
  60% { transform: translateY(0.075px) scale(1); }
  70% { transform: translate(-0.075px, -0.1px) scale(1); }
  80% { transform: translate(0.075px, 0.125px) scale(1); }
  90% { transform: translate(-0.125px, -0.075px) scale(1); }
  100% { transform: translate(0.075px, 0.025px) scale(1); }
}

@keyframes code-block-module__NOThwW__hide { 
  0% { opacity: 1; transform: translate(-50%, -50%); }
  20% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
  80% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
  100% { opacity: 1; transform: translate(-50%, -50%); }
}

@keyframes code-block-module__NOThwW__show { 
  0% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
  20% { opacity: 1; transform: translate(-50%, -50%); }
  60% { opacity: 1; transform: translate(-50%, -50%); }
  80% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
  100% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
}

@keyframes navigation-menu-module__AENi4G__scaleIn { 
  0% { opacity: 0; transform: rotateX(-30deg) scale(0.9); }
  100% { opacity: 1; transform: rotateX(0deg) scale(1); }
}

@keyframes navigation-menu-module__AENi4G__scaleOut { 
  0% { opacity: 1; transform: rotateX(0deg) scale(1); }
  100% { opacity: 0; transform: rotateX(-10deg) scale(0.95); }
}

@keyframes navigation-menu-module__AENi4G__enterFromRight { 
  0% { opacity: 0; transform: translate(200px); }
  100% { opacity: 1; transform: translate(0px); }
}

@keyframes navigation-menu-module__AENi4G__enterFromLeft { 
  0% { opacity: 0; transform: translate(-200px); }
  100% { opacity: 1; transform: translate(0px); }
}

@keyframes navigation-menu-module__AENi4G__exitToRight { 
  0% { opacity: 1; transform: translate(0px); }
  100% { opacity: 0; transform: translate(200px); }
}

@keyframes navigation-menu-module__AENi4G__exitToLeft { 
  0% { opacity: 1; transform: translate(0px); }
  100% { opacity: 0; transform: translate(-200px); }
}

@keyframes navigation-menu-module__AENi4G__slideUp { 
  0% { opacity: 1; transform: translateY(0px); }
  100% { opacity: 0; transform: translateY(-8px); }
}

@keyframes customer-carousel-module__pFnISG__scroll { 
  0% { transform: translate(0px, 0px); }
  100% { transform: translate3d(calc(100% / var(--copies) * -1), 0, 0); }
}

@keyframes v0-cursor-reveal-module__eaE5iq__fluctuate { 
  0% { opacity: 1; height: 0px; }
  10% { opacity: 1; height: 24px; }
  45% { opacity: 1; height: 24px; }
  80% { opacity: 1; height: 55.92px; }
  82.5% { opacity: 1; height: 55.92px; }
  96.5% { opacity: 1; height: 0px; }
  100% { opacity: 1; height: 0px; }
}

@keyframes show { 
  0% { transform: translate3d(0, var(--translate-y-start), 0); opacity: 0; }
  100% { transform: translate3d(0, var(--translate-y-end), 0); opacity: 1; }
}

@keyframes hide { 
  0% { transform: translate3d(0, var(--translate-y-end), 0); opacity: 1; }
  100% { transform: translate3d(0, var(--translate-y-start), 0); opacity: 0; }
}

@keyframes show { 
  0% { transform: translate3d(0, var(--translate-y-start), 0); opacity: 0; }
  100% { transform: translate3d(0, var(--translate-y-end), 0); opacity: 1; }
}

@keyframes hide { 
  0% { transform: translate3d(0, var(--translate-y-end), 0); opacity: 1; }
  100% { transform: translate3d(0, var(--translate-y-start), 0); opacity: 0; }
}

@keyframes modal-appear { 
  0% { opacity: 0; transform: translateY(20px); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes bounce { 
  0%, 100% { animation-timing-function: cubic-bezier(0.8, 0, 1, 1); transform: translateY(-25%); }
  50% { animation-timing-function: cubic-bezier(0, 0, 0.2, 1); transform: none; }
}

@keyframes logo-carousel { 
  0% { opacity: 0; }
  3% { opacity: 1; }
  22% { opacity: 1; }
  25% { opacity: 0; }
  100% { opacity: 0; }
}

@keyframes sandbox-left { 
  0% { transform: translate(0px) rotate(0deg); }
  50% { transform: translate(-80px) rotate(-6deg); }
  100% { z-index: 0; opacity: 0.5; transform: translate(0px) rotate(0deg); }
}

@keyframes sandbox-left-reverse { 
  0% { z-index: 0; opacity: 0.5; transform: translate(0px) rotate(0deg); }
  50% { transform: translate(-80px) rotate(-6deg); }
  100% { z-index: 10; opacity: 1; transform: translate(0px) rotate(0deg); }
}

@keyframes sandbox-right { 
  0% { transform: translate(0px) rotate(0deg); }
  50% { transform: translate(80px) rotate(6deg); }
  100% { z-index: 10; transform: translate(0px) rotate(0deg); }
}

@keyframes sandbox-right-reverse { 
  0% { z-index: 10; transform: translate(0px) rotate(0deg); }
  50% { transform: translate(80px) rotate(6deg); }
  100% { z-index: 0; transform: translate(0px) rotate(0deg); }
}

@keyframes slide-in { 
  0% { opacity: 0; transform: translateY(75%); }
  100% { opacity: 1; transform: translateY(0px); }
}

@keyframes enter { 
  0% { opacity: var(--tw-enter-opacity,1); transform: translate3d(var(--tw-enter-translate-x,0), var(--tw-enter-translate-y,0), 0) scale3d(var(--tw-enter-scale,1), var(--tw-enter-scale,1), var(--tw-enter-scale,1)) rotate(var(--tw-enter-rotate,0)); }
}

@keyframes exit { 
  100% { opacity: var(--tw-exit-opacity,1); transform: translate3d(var(--tw-exit-translate-x,0), var(--tw-exit-translate-y,0), 0) scale3d(var(--tw-exit-scale,1), var(--tw-exit-scale,1), var(--tw-exit-scale,1)) rotate(var(--tw-exit-rotate,0)); }
}

@keyframes blue-glow { 
  0%, 100% { content: var(--tw-content); box-shadow: 0 0 10px var(--ds-blue-200), 0 0 20px var(--ds-blue-100); }
  50% { content: var(--tw-content); box-shadow: 0 0 30px var(--ds-blue-400), 0 0 60px var(--ds-blue-200); }
}

@keyframes turbohero-background-module__x12i7q__pulse-frames { 
  0% { transform: translateY(0%); }
  50% { transform: translateY(200%); }
  100% { transform: translateY(200%); }
}

@keyframes turbohero-module__73qp5G__spin { 
  0% { transform: translate(-50%, -50%) rotate(360deg); }
  100% { transform: translate(-50%, -50%) rotate(0deg); }
}

@keyframes tabbed-code-block-module__GvcU7W__hide { 
  0% { opacity: 1; transform: translate(-50%, -50%); }
  20% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
  80% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
  100% { opacity: 1; transform: translate(-50%, -50%); }
}

@keyframes tabbed-code-block-module__GvcU7W__show { 
  0% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
  20% { opacity: 1; transform: translate(-50%, -50%); }
  60% { opacity: 1; transform: translate(-50%, -50%); }
  80% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
  100% { opacity: 0; transform: translate(-50%, -50%) scale(0.5); }
}

@keyframes cursor-module__AEUiAq__float { 
  0% { transform: translate(0px); }
  50% { transform: translate(var(--x), var(--y)); }
  100% { transform: translate(0px); }
}

@keyframes codeblock-module__Ybl_QW__blastIn { 
  0% { opacity: 0; filter: blur(4px); transform: scale(1.1); }
  100% { opacity: 1; filter: blur(); transform: scale(1); }
}

rules.cssText:
@supports (color:oklch(0% 0 0)) {
  :root, :host, .dark .invert-theme, .dark-theme .invert-theme, .geist-disabled .geist-disabled-skip { --develop-start-gradient: oklch(59.59% .24 255.092); --develop-end-gradient: oklch(81.58% .189 190.74); --develop-line-end: oklch(65.84% .203 242.532); --develop-text: oklch(57.49% .249 257.84); --preview-start-gradient: oklch(49.07% .272 300.45); --preview-end-gradient: oklch(64.53% .292 2.47); --preview-line-end: oklch(51.39% .267 318.36); --preview-text: oklch(59.93% .274 352.55); --ship-start-gradient: oklch(67.3% .266 25.0397); --ship-end-gradient: oklch(85.82% .201 91.19); --ship-line-end: oklch(85.82% .201 91.19); --ship-text: oklch(68.79% .25 27.76); }
}

@keyframes marquee { 
  0% { transform: translate(0px); }
  100% { transform: translateX(calc(-100% - var(--marquee-gap))); }
}

@media (prefers-reduced-motion: no-preference) {
  @keyframes marquee { 
  0% { transform: translate(0px); }
  100% { transform: translateX(calc(-100% - var(--marquee-gap))); }
}
  .tailwind .lg\:motion-safe\:animate-marquee { animation: marquee var(--marquee-speed,40s) linear infinite; }
}
